  1→/**
  2→ * Agent Query Functions
  3→ *
  4→ * SurrealDB graph traversal, atomic creation transactions, and
  5→ * atomic deletion transactions for the agent CRUD module.
  6→ *
  7→ * All functions take `surreal` as first parameter (dependency injection).
  8→ * No module-level singletons or mutable state.
  9→ */
 10→import { randomUUID } from "node:crypto";
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import { HttpError } from "../http/errors";
 13→import {
 14→  generateProxyToken,
 15→  hashProxyToken,
 16→  computeExpiresAt,
 17→  readProxyTokenTtlDays,
 18→} from "../proxy/proxy-token-core";
 19→import {
 20→  AUTHORITY_ACTIONS,
 21→  type AgentDetail,
 22→  type AgentListItem,
 23→  type AuthorityAction,
 24→  type AuthorityPermission,
 25→  type CreateAgentInput,
 26→  type CreateAgentResult,
 27→  type DeleteAgentResult,
 28→  type SandboxConfig,
 29→  type SessionSummary,
 30→} from "./types";
 31→
 32→// ---------------------------------------------------------------------------
 33→// List agents
 34→// ---------------------------------------------------------------------------
 35→
 36→type ListAgentRow = {
 37→  id: RecordId<"identity_agent", string>;
 38→  agent_id: RecordId<"agent", string>;
 39→  agent_name: string;
 40→  agent_description?: string;
 41→  agent_runtime: string;
 42→  agent_model?: string;
 43→  identity_id: RecordId<"identity", string>;
 44→  agent_created_at: string | Date;
 45→};
 46→
 47→/**
 48→ * List all agents in a workspace via graph traversal:
 49→ * workspace <- member_of <- identity <- identity_agent -> agent
 50→ */
 51→export async function listAgents(
 52→  surreal: Surreal,
 53→  workspaceId: string,
 54→): Promise<AgentListItem[]> {
 55→  const workspaceRecord = new RecordId("workspace", workspaceId);
 56→
 57→  const [rows] = await surreal
 58→    .query<[ListAgentRow[]]>(
 59→      `SELECT
 60→        id,
 61→        out.id AS agent_id,
 62→        out.name AS agent_name,
 63→        out.description AS agent_description,
 64→        out.runtime AS agent_runtime,
 65→        out.model AS agent_model,
 66→        in.id AS identity_id,
 67→        out.created_at AS agent_created_at
 68→      FROM identity_agent
 69→      WHERE in IN (
 70→        SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
 71→      )
 72→      ORDER BY agent_created_at DESC;`,
 73→      { ws: workspaceRecord },
 74→    );
 75→
 76→  return rows.map(toAgentListItem);
 77→}
 78→
 79→function toAgentListItem(row: ListAgentRow): AgentListItem {
 80→  return {
 81→    id: row.agent_id.id as string,
 82→    name: row.agent_name,
 83→    ...(row.agent_description ? { description: row.agent_description } : {}),
 84→    runtime: row.agent_runtime as AgentListItem["runtime"],
 85→    ...(row.agent_model ? { model: row.agent_model } : {}),
 86→    identity_id: row.identity_id.id as string,
 87→    created_at: toISOString(row.agent_created_at),
 88→  };
 89→}
 90→
 91→// ---------------------------------------------------------------------------
 92→// Check agent name availability
 93→// ---------------------------------------------------------------------------
 94→
 95→/**
 96→ * Check if an agent name is available within a workspace.
 97→ * Returns true if the name is not taken.
 98→ */
 99→export async function checkAgentName(
100→  surreal: Surreal,
101→  workspaceId: string,
102→  name: string,
103→): Promise<boolean> {
104→  const workspaceRecord = new RecordId("workspace", workspaceId);
105→
106→  const [rows] = await surreal
107→    .query<[Array<{ agent_name: string }>]>(
108→      `SELECT out.name AS agent_name
109→      FROM identity_agent
110→      WHERE in IN (
111→        SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
112→      )
113→      AND out.name = $name
114→      LIMIT 1;`,
115→      { ws: workspaceRecord, name },
116→    );
117→
118→  return rows.length === 0;
119→}
120→
121→// ---------------------------------------------------------------------------
122→// Create agent (atomic transaction)
123→// ---------------------------------------------------------------------------
124→
125→/**
126→ * Create an agent with identity, membership, authority scopes, and
127→ * optional proxy token in a single atomic transaction.
128→ *
129→ * Steps:
130→ * 1. Validate name uniqueness within workspace
131→ * 2. CREATE agent record
132→ * 3. CREATE identity record
133→ * 4. RELATE identity -> identity_agent -> agent
134→ * 5. RELATE identity -> member_of -> workspace
135→ * 6. For each of 11 actions: RELATE identity -> authorized_to -> authority_scope
136→ * 7. For external agents: generate and store proxy token
137→ */
138→export async function createAgentTransaction(
139→  surreal: Surreal,
140→  workspaceId: string,
141→  input: CreateAgentInput,
142→  now: Date,
143→): Promise<CreateAgentResult> {
144→  // Pre-validate name uniqueness
145→  const nameAvailable = await checkAgentName(surreal, workspaceId, input.name);
146→  if (!nameAvailable) {
147→    throw new HttpError(409, `Agent name '${input.name}' is already taken in this workspace`);
148→  }
149→
150→  const workspaceRecord = new RecordId("workspace", workspaceId);
151→  const agentId = randomUUID();
152→  const identityId = randomUUID();
153→  const agentRecord = new RecordId("agent", agentId);
154→  const identityRecord = new RecordId("identity", identityId);
155→
156→  // Build permission map from input, defaulting unconfigured actions to "propose"
157→  const permissionMap = buildPermissionMap(input.authority_scopes);
158→
159→  // Look up all authority_scope records for our actions to get the OUT targets
160→  const [scopeRows] = await surreal
161→    .query<[Array<{ id: RecordId<"authority_scope", string>; action: string }>]>(
162→      `SELECT id, action FROM authority_scope
163→       WHERE action IN $actions
164→       AND workspace IS NONE;`,
165→      { actions: [...AUTHORITY_ACTIONS] },
166→    );
167→
168→  const scopeByAction = new Map(
169→    scopeRows.map((row) => [row.action, row.id]),
170→  );
171→
172→  // Build the transaction SQL
173→  const statements: string[] = [];
174→  const bindings: Record<string, unknown> = {
175→    agentRecord,
176→    identityRecord,
177→    wsRecord: workspaceRecord,
178→    agentName: input.name,
179→    agentRuntime: input.runtime,
180→    agentType: "mcp", // custom agents default to "mcp" agent_type
181→    now,
182→  };
183→
184→  // Step 2: CREATE agent
185→  statements.push(
186→    `CREATE $agentRecord CONTENT {
187→      agent_type: $agentType,
188→      runtime: $agentRuntime,
189→      name: $agentName,
190→      ${input.description ? "description: $agentDescription," : ""}
191→      ${input.model ? "model: $agentModel," : ""}
192→      managed_by: $identityRecord,
193→      created_at: $now
194→      ${input.sandbox_config ? ", sandbox_config: $sandboxConfig" : ""}
195→    };`,
196→  );
197→
198→  if (input.description) bindings.agentDescription = input.description;
199→  if (input.model) bindings.agentModel = input.model;
200→  if (input.sandbox_config) bindings.sandboxConfig = input.sandbox_config;
201→
202→  // Step 3: CREATE identity
203→  statements.push(
204→    `CREATE $identityRecord CONTENT {
205→      name: $agentName,
206→      type: 'agent',
207→      role: 'custom',
208→      identity_status: 'active',
209→      workspace: $wsRecord,
210→      created_at: $now
211→    };`,
212→  );
213→
214→  // Step 4: RELATE identity -> identity_agent -> agent
215→  const identityAgentId = randomUUID();
216→  bindings.identityAgentRecord = new RecordId("identity_agent", identityAgentId);
217→  statements.push(
218→    `RELATE $identityRecord -> identity_agent -> $agentRecord
219→     CONTENT { added_at: $now };`,
220→  );
221→
222→  // Step 5: RELATE identity -> member_of -> workspace
223→  statements.push(
224→    `RELATE $identityRecord -> member_of -> $wsRecord
225→     CONTENT { role: 'agent', added_at: $now };`,
226→  );
227→
228→  // Step 6: RELATE identity -> authorized_to -> authority_scope for each action
229→  for (const action of AUTHORITY_ACTIONS) {
230→    const scopeRecord = scopeByAction.get(action);
231→    if (!scopeRecord) continue; // Skip if no global scope exists for this action
232→
233→    const permission = permissionMap.get(action) ?? "propose";
234→    const bindKey = `scope_${action}`;
235→    const permKey = `perm_${action}`;
236→    bindings[bindKey] = scopeRecord;
237→    bindings[permKey] = permission;
238→
239→    statements.push(
240→      `RELATE $identityRecord -> authorized_to -> $${bindKey}
241→       CONTENT { permission: $${permKey}, created_at: $now };`,
242→    );
243→  }
244→
245→  // Step 7: For external agents, generate proxy token
246→  let plainToken: string | undefined;
247→  if (input.runtime === "external") {
248→    plainToken = generateProxyToken();
249→    const tokenHash = hashProxyToken(plainToken);
250→    const ttlDays = readProxyTokenTtlDays();
251→    const expiresAt = computeExpiresAt(ttlDays, now);
252→    const proxyTokenId = randomUUID();
253→
254→    bindings.proxyTokenRecord = new RecordId("proxy_token", proxyTokenId);
255→    bindings.tokenHash = tokenHash;
256→    bindings.expiresAt = expiresAt;
257→
258→    statements.push(
259→      `CREATE $proxyTokenRecord CONTENT {
260→        token_hash: $tokenHash,
261→        workspace: $wsRecord,
262→        identity: $identityRecord,
263→        expires_at: $expiresAt,
264→        created_at: $now,
265→        revoked: false
266→      };`,
267→    );
268→  }
269→
270→  // Execute all statements in a single transaction
271→  const transactionSql = `BEGIN TRANSACTION;\n${statements.join("\n")}\nCOMMIT TRANSACTION;`;
272→  await surreal.query(transactionSql, bindings);
273→
274→  const agentListItem: AgentListItem = {
275→    id: agentId,
276→    name: input.name,
277→    ...(input.description ? { description: input.description } : {}),
278→    runtime: input.runtime,
279→    ...(input.model ? { model: input.model } : {}),
280→    identity_id: identityId,
281→    created_at: now.toISOString(),
282→  };
283→
284→  return {
285→    agent: agentListItem,
286→    ...(plainToken ? { proxy_token: plainToken } : {}),
287→  };
288→}
289→
290→function buildPermissionMap(
291→  scopes?: Array<{ action: AuthorityAction; permission: AuthorityPermission }>,
292→): Map<AuthorityAction, AuthorityPermission> {
293→  const map = new Map<AuthorityAction, AuthorityPermission>();
294→  if (!scopes) return map;
295→  for (const scope of scopes) {
296→    map.set(scope.action, scope.permission);
297→  }
298→  return map;
299→}
300→
301→// ---------------------------------------------------------------------------
302→// Get agent detail
303→// ---------------------------------------------------------------------------
304→
305→type AgentDetailRow = {
306→  id: RecordId<"agent", string>;
307→  name: string;
308→  description?: string;
309→  runtime: string;
310→  model?: string;
311→  sandbox_config?: SandboxConfig;
312→  created_at: string | Date;
313→};
314→
315→type IdentityRow = {
316→  id: RecordId<"identity", string>;
317→  name: string;
318→  type: string;
319→  role?: string;
320→};
321→
322→type AuthorizedToRow = {
323→  action: string;
324→  permission: string;
325→};
326→
327→type SessionRow = {
328→  id: RecordId<"agent_session", string>;
329→  started_at: string | Date;
330→  ended_at?: string | Date;
331→  orchestrator_status?: string;
332→  summary?: string;
333→};
334→
335→/**
336→ * Get full agent detail including identity, authority scopes, and
337→ * recent workspace sessions.
338→ */
339→export async function getAgentDetail(
340→  surreal: Surreal,
341→  workspaceId: string,
342→  agentId: string,
343→): Promise<AgentDetail | undefined> {
344→  const workspaceRecord = new RecordId("workspace", workspaceId);
345→  const agentRecord = new RecordId("agent", agentId);
346→
347→  // Query agent, identity, authorized_to edges, and sessions in one round-trip
348→  const results = await surreal
349→    .query<[AgentDetailRow[], IdentityRow[], AuthorizedToRow[], SessionRow[]]>(
350→      `SELECT id, name, description, runtime, model, sandbox_config, created_at
351→       FROM $agent;
352→
353→       SELECT id, name, type, role
354→       FROM identity
355→       WHERE id IN (
356→         SELECT VALUE in FROM identity_agent WHERE out = $agent
357→       )
358→       AND workspace = $ws
359→       LIMIT 1;
360→
361→       SELECT out.action AS action, permission
362→       FROM authorized_to
363→       WHERE in IN (
364→         SELECT VALUE in FROM identity_agent WHERE out = $agent
365→       )
366→       ORDER BY action ASC;
367→
368→       SELECT id, started_at, ended_at, orchestrator_status, summary
369→       FROM agent_session
370→       WHERE workspace = $ws
371→       ORDER BY started_at DESC
372→       LIMIT 20;`,
373→      { agent: agentRecord, ws: workspaceRecord },
374→    );
375→
376→  const [agentRows, identityRows, authorizedToRows, sessionRows] = results;
377→
378→  if (agentRows.length === 0 || identityRows.length === 0) {
379→    return undefined;
380→  }
381→
382→  const agentRow = agentRows[0];
383→  const identityRow = identityRows[0];
384→
385→  const agentListItem: AgentDetail["agent"] = {
386→    id: agentRow.id.id as string,
387→    name: agentRow.name,
388→    ...(agentRow.description ? { description: agentRow.description } : {}),
389→    runtime: agentRow.runtime as AgentListItem["runtime"],
390→    ...(agentRow.model ? { model: agentRow.model } : {}),
391→    identity_id: identityRow.id.id as string,
392→    created_at: toISOString(agentRow.created_at),
393→    ...(agentRow.sandbox_config ? { sandbox_config: agentRow.sandbox_config } : {}),
394→  };
395→
396→  return {
397→    agent: agentListItem,
398→    identity: {
399→      id: identityRow.id.id as string,
400→      name: identityRow.name,
401→      type: identityRow.type,
402→      ...(identityRow.role ? { role: identityRow.role } : {}),
403→    },
404→    authority_scopes: authorizedToRows.map((row) => ({
405→      action: row.action,
406→      permission: row.permission,
407→    })),
408→    sessions: sessionRows.map(toSessionSummary),
409→  };
410→}
411→
412→function toSessionSummary(row: SessionRow): SessionSummary {
413→  return {
414→    id: row.id.id as string,
415→    started_at: toISOString(row.started_at),
416→    ...(row.ended_at ? { ended_at: toISOString(row.ended_at) } : {}),
417→    ...(row.orchestrator_status ? { orchestrator_status: row.orchestrator_status } : {}),
418→    ...(row.summary ? { summary: row.summary } : {}),
419→  };
420→}
421→
422→// ---------------------------------------------------------------------------
423→// Delete agent (atomic transaction)
424→// ---------------------------------------------------------------------------
425→
426→/**
427→ * Delete an agent and all associated records atomically.
428→ *
429→ * Validates:
430→ * - Agent exists in workspace
431→ * - Agent is not a brain-managed agent
432→ * - Confirmation name matches agent name
433→ *
434→ * Deletes:
435→ * 1. authorized_to edges from identity
436→ * 2. proxy_token records for identity
437→ * 3. member_of edges from identity to workspace
438→ * 4. identity_agent edges to agent
439→ * 5. identity record
440→ * 6. agent record
441→ */
442→export async function deleteAgentTransaction(
443→  surreal: Surreal,
444→  workspaceId: string,
445→  agentId: string,
446→  confirmName: string,
447→): Promise<DeleteAgentResult> {
448→  const workspaceRecord = new RecordId("workspace", workspaceId);
449→  const agentRecord = new RecordId("agent", agentId);
450→
451→  // Validate agent exists and fetch identity
452→  const [agentRows, identityRows] = await surreal
453→    .query<[
454→      Array<{ id: RecordId; name: string; runtime: string }>,
455→      Array<{ id: RecordId<"identity", string> }>,
456→    ]>(
457→      `SELECT id, name, runtime FROM $agent;
458→
459→       SELECT VALUE in FROM identity_agent
460→       WHERE out = $agent
461→       AND in IN (
462→         SELECT VALUE in FROM member_of WHERE out = $ws AND in.type = 'agent'
463→       )
464→       LIMIT 1;`,
465→      { agent: agentRecord, ws: workspaceRecord },
466→    );
467→
468→  if (agentRows.length === 0) {
469→    throw new HttpError(404, "Agent not found");
470→  }
471→
472→  const agent = agentRows[0];
473→
474→  if (agent.runtime === "brain") {
475→    throw new HttpError(403, "Cannot delete brain-managed agents");
476→  }
477→
478→  if (agent.name !== confirmName) {
479→    throw new HttpError(
480→      400,
481→      `Confirmation name '${confirmName}' does not match agent name '${agent.name}'`,
482→    );
483→  }
484→
485→  if (identityRows.length === 0) {
486→    throw new HttpError(404, "Agent identity not found in workspace");
487→  }
488→
489→  const identityRecord = identityRows[0] as unknown as RecordId<"identity", string>;
490→
491→  // Execute deletion in a single transaction
492→  await surreal.query(
493→    `BEGIN TRANSACTION;
494→     DELETE FROM authorized_to WHERE in = $identity;
495→     DELETE FROM proxy_token WHERE identity = $identity;
496→     DELETE FROM member_of WHERE in = $identity AND out = $ws;
497→     DELETE FROM identity_agent WHERE out = $agent;
498→     DELETE $identity;
499→     DELETE $agent;
500→     COMMIT TRANSACTION;`,
501→    {
502→      identity: identityRecord,
503→      agent: agentRecord,
504→      ws: workspaceRecord,
505→    },
506→  );
507→
508→  return {
509→    deleted: true,
510→    sessions_aborted: 0, // Deferred to R2
511→  };
512→}
513→
514→// ---------------------------------------------------------------------------
515→// Helpers
516→// ---------------------------------------------------------------------------
517→
518→function toISOString(value: string | Date): string {
519→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
520→}
